   210→              );
   211→            }
   212→
   213→            if (key === "title") {
   214→              return (
   215→                <div key={key} className="prop-field">
   216→                  <EditableValue
   217→                    fieldKey={key}
   218→                    value={val}
   219→                    onSave={(v) => onFieldChange?.(key, v)}
   220→                  />
