   326→/// Search all markdown files under `path` for lines containing `query` (case-insensitive).
   327→fn search_dir(path: &Path, query: &str) -> Vec<SearchResult> {
   328→    let Ok(entries) = std::fs::read_dir(path) else {
   329→        return Vec::new();
   330→    };
   331→    let mut entries: Vec<_> = entries.flatten().collect();
   332→    entries.sort_by_key(|e| e.file_name());
   333→
   334→    let mut results = Vec::new();
   335→    for entry in entries {
   336→        let entry_path = entry.path();
   337→        let name = entry.file_name().to_string_lossy().to_string();
   338→        if name.starts_with('.') {
   339→            continue;
   340→        }
   341→        // Skip symlinks to prevent traversal outside the workspace
   342→        if entry.file_type().map(|ft| ft.is_symlink()).unwrap_or(false) {
   343→            continue;
   344→        }
   345→        if entry_path.is_dir() {
   346→            results.extend(search_dir(&entry_path, query));
   347→        } else {
   348→            let ext = entry_path.extension().and_then(|e| e.to_str()).unwrap_or("");
   349→            if ext != "md" && ext != "mdx" {
   350→                continue;
   351→            }
   352→            let Ok(content) = std::fs::read_to_string(&entry_path) else {
   353→                continue;
   354→            };
   355→            let q = query.to_lowercase();
   356→            let matches: Vec<SearchMatch> = content
   357→                .lines()
   358→                .enumerate()
   359→                .filter_map(|(i, line)| {
   360→                    if line.to_lowercase().contains(&q) {
   361→                        Some(SearchMatch {
   362→                            line_number: i + 1,
   363→                            line_content: line.trim().to_string(),
   364→                        })
   365→                    } else {
   366→                        None
   367→                    }
   368→                })
   369→                .collect();
   370→            if !matches.is_empty() {
   371→                let (title, _) = read_frontmatter_meta(&entry_path);
   372→                results.push(SearchResult {
   373→                    path: entry_path.to_string_lossy().to_string(),
   374→                    title,
   375→                    matches,
   376→                });
   377→            }
   378→        }
   379→    }
   380→    results
   381→}
