   383→#[tauri::command]
   384→fn search_workspace(query: String, state: State<'_, WorkspaceState>) -> Result<Vec<SearchResult>, String> {
   385→    if query.trim().is_empty() {
   386→        return Ok(Vec::new());
   387→    }
   388→    // Clone root before releasing the lock so the mutex is not held during search
   389→    let root = {
   390→        let root_guard = state.tree_root.lock().map_err(|e| e.to_string())?;
   391→        root_guard.as_ref().ok_or("no workspace open")?.clone()
   392→    };
