   407→// ── Content types ──────────────────────────────────────────────────────────
   408→
   409→#[derive(Serialize)]
   410→#[serde(rename_all = "camelCase")]
   411→struct ContentType {
   412→    name: String,
   413→}
   414→
   415→/// Best-effort scanner: find `contentTypes` in `site.config.ts` and extract
   416→/// the top-level key names (post, page, note, …). Returns empty vec on any
   417→/// parse failure so callers gracefully degrade to the default frontmatter.
   418→fn parse_content_types(config_path: &Path) -> Vec<ContentType> {
   419→    use std::io::{BufRead, BufReader};
   420→    let Ok(file) = std::fs::File::open(config_path) else {
   421→        return Vec::new();
   422→    };
   423→    let mut reader = BufReader::new(file);
   424→    let mut type_names: Vec<ContentType> = Vec::new();
   425→    let mut depth: i32 = 0;
   426→    let mut found_content_types = false;
   427→    let mut content_types_depth: Option<i32> = None;
   428→    let mut line = String::new();
   429→
   430→    loop {
   431→        line.clear();
   432→        if reader.read_line(&mut line).unwrap_or(0) == 0 {
   433→            break;
   434→        }
   435→        let trimmed = line.trim();
   436→        let open_count = line.chars().filter(|&c| c == '{').count() as i32;
   437→        let close_count = line.chars().filter(|&c| c == '}').count() as i32;
   438→
   439→        match content_types_depth {
   440→            None if !found_content_types => {
   441→                if trimmed.contains("contentTypes") {
   442→                    found_content_types = true;
   443→                    depth += open_count - close_count;
   444→                    if open_count > 0 {
   445→                        content_types_depth = Some(depth);
   446→                    }
   447→                } else {
   448→                    depth += open_count - close_count;
   449→                }
   450→            }
   451→            None => {
   452→                // found keyword, waiting for opening brace
   453→                depth += open_count - close_count;
   454→                if open_count > 0 {
   455→                    content_types_depth = Some(depth);
   456→                }
   457→            }
   458→            Some(ct_depth) => {
   459→                let prev_depth = depth;
   460→                depth += open_count - close_count;
   461→                if depth < ct_depth {
   462→                    break;
   463→                }
   464→                if prev_depth == ct_depth {
   465→                    if let Some(name) = extract_ts_key(trimmed) {
   466→                        type_names.push(ContentType { name });
   467→                    }
   468→                }
   469→            }
   470→        }
   471→    }
   472→    type_names
   473→}
   474→
   475→fn extract_ts_key(line: &str) -> Option<String> {
   476→    let line = line.trim();
   477→    if line.starts_with("//") || line.starts_with('*') || line.starts_with("/*") {
   478→        return None;
   479→    }
   480→    let end = line.find(':')?;
   481→    let key = line[..end].trim().trim_matches('"').trim_matches('\'');
   482→    if !key.is_empty() && key.chars().all(|c| c.is_alphanumeric() || c == '_') {
   483→        Some(key.to_string())
   484→    } else {
   485→        None
   486→    }
   487→}
