   504→// ── Git integration ────────────────────────────────────────────────────────
   505→
   506→#[derive(Serialize)]
   507→#[serde(rename_all = "camelCase")]
   508→struct GitFileStatus {
   509→    path: String,
   510→    status: String,
   511→}
   512→
   513→/// Run a git subcommand rooted at `root`. Returns stdout on success or an
   514→/// error string (stderr) on failure. Returns an empty string if git is not
   515→/// found, so callers can treat a missing git as a graceful no-op.
   516→fn run_git(root: &str, args: &[&str]) -> Result<String, String> {
   517→    let mut cmd_args = vec!["-C", root];
   518→    cmd_args.extend_from_slice(args);
   519→    let output = std::process::Command::new("git")
   520→        .args(&cmd_args)
   521→        .output()
   522→        .map_err(|_| "git not found".to_string())?;
   523→    if !output.status.success() {
   524→        let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
   525→        return Err(if stderr.is_empty() { "git command failed".to_string() } else { stderr });
   526→    }
   527→    Ok(String::from_utf8_lossy(&output.stdout).to_string())
   528→}
   529→
   530→#[tauri::command]
   531→fn get_git_status(state: State<'_, WorkspaceState>) -> Result<Vec<GitFileStatus>, String> {
   532→    let root_guard = state.tree_root.lock().map_err(|e| e.to_string())?;
   533→    let root = match root_guard.as_ref() {
   534→        Some(r) => r.clone(),
   535→        None => return Ok(Vec::new()),
   536→    };
   537→    drop(root_guard);
   538→    let root_str = root.to_string_lossy().to_string();
   539→
   540→    // Find the git repo root (may differ from tree_root if content/ is a subdir)
   541→    let git_root = match run_git(&root_str, &["rev-parse", "--show-toplevel"]) {
   542→        Ok(s) => s.trim().to_string(),
   543→        Err(_) => return Ok(Vec::new()), // not a git repo or git not found
   544→    };
   545→
   546→    let porcelain = match run_git(&git_root, &["status", "--porcelain"]) {
   547→        Ok(s) => s,
   548→        Err(_) => return Ok(Vec::new()),
   549→    };
   550→
   551→    let mut statuses = Vec::new();
   552→    for line in porcelain.lines() {
   553→        if line.len() < 4 {
   554→            continue;
   555→        }
   556→        let xy = &line[..2];
   557→        let path_part = line[3..].trim();
   558→        // Handle renames: "R old -> new" — take the destination
   559→        let file_path = if path_part.contains(" -> ") {
   560→            path_part.split(" -> ").nth(1).unwrap_or(path_part)
   561→        } else {
   562→            path_part
   563→        };
   564→        let abs_path = PathBuf::from(&git_root).join(file_path).to_string_lossy().into_owned();
   565→        let status = if xy.starts_with('?') {
   566→            "untracked"
   567→        } else if xy.chars().next().map(|c| c != ' ').unwrap_or(false) {
   568→            "staged"
   569→        } else {
   570→            "modified"
   571→        };
   572→        statuses.push(GitFileStatus { path: abs_path, status: status.to_string() });
   573→    }
   574→    Ok(statuses)
   575→}
   576→
   577→#[tauri::command]
   578→fn get_git_branch(state: State<'_, WorkspaceState>) -> Result<String, String> {
   579→    let root_guard = match state.tree_root.lock() {
   580→        Ok(g) => g,
   581→        Err(_) => return Ok(String::new()),
   582→    };
   583→    let root = match root_guard.as_ref() {
   584→        Some(r) => r.clone(),
   585→        None => return Ok(String::new()),
   586→    };
   587→    drop(root_guard);
   588→    Ok(
   589→        run_git(&root.to_string_lossy(), &["rev-parse", "--abbrev-ref", "HEAD"])
   590→            .map(|s| s.trim().to_string())
   591→            .unwrap_or_default(),
   592→    )
   593→}
