   595→#[tauri::command]
   596→fn git_commit(
   597→    message: String,
   598→    push: bool,
   599→    state: State<'_, WorkspaceState>,
   600→) -> Result<(), String> {
   601→    let root_guard = state.tree_root.lock().map_err(|e| e.to_string())?;
   602→    let root = root_guard.as_ref().ok_or("no workspace open")?.clone();
   603→    drop(root_guard);
   604→    let root_str = root.to_string_lossy().to_string();
   605→    run_git(&root_str, &["add", "-A"])?;
   606→    run_git(&root_str, &["commit", "-m", &message])?;
   607→    if push {
   608→        run_git(&root_str, &["push"])?;
   609→    }
   610→    Ok(())
   611→}
