   628→/// Copy an image from an arbitrary path into `<workspace>/assets/` and return
   629→/// a path relative to the active markdown file (or `assets/<name>` as fallback).
   630→///
   631→/// Note: unlike `read_file`/`write_file`, `src_path` is intentionally not
   632→/// validated against the workspace root — drag-and-drop sources originate from
   633→/// external locations (desktop, downloads, etc.). The destination is safely
   634→/// constrained to `<workspace>/assets/`.
   635→#[tauri::command]
   636→fn save_asset(
   637→    src_path: String,
   638→    active_file_path: Option<String>,
   639→    state: State<'_, WorkspaceState>,
   640→) -> Result<String, String> {
   641→    let root_guard = state.tree_root.lock().map_err(|e| e.to_string())?;
   642→    let root = root_guard.as_ref().ok_or("no workspace open")?.clone();
   643→    drop(root_guard);
   644→
   645→    let src = Path::new(&src_path);
   646→    let file_name = src
   647→        .file_name()
   648→        .ok_or("invalid source path")?
   649→        .to_string_lossy()
   650→        .to_string();
   651→
   652→    let assets_dir = root.join("assets");
   653→    std::fs::create_dir_all(&assets_dir)
   654→        .map_err(|e| format!("could not create assets dir: {e}"))?;
   655→
   656→    // Atomically reserve a destination path to avoid TOCTOU races.
   657→    // Try the original name first; fall back to timestamp-prefixed candidates.
   658→    let dest_name = match std::fs::OpenOptions::new()
   659→        .write(true)
   660→        .create_new(true)
   661→        .open(assets_dir.join(&file_name))
   662→    {
   663→        Ok(_) => file_name.clone(),
   664→        Err(e) if e.kind() == std::io::ErrorKind::AlreadyExists => loop {
   665→            let ts = std::time::SystemTime::now()
   666→                .duration_since(std::time::UNIX_EPOCH)
   667→                .map(|d| d.as_millis())
   668→                .unwrap_or(0);
   669→            let candidate = format!("{ts}_{file_name}");
   670→            match std::fs::OpenOptions::new()
   671→                .write(true)
   672→                .create_new(true)
   673→                .open(assets_dir.join(&candidate))
   674→            {
   675→                Ok(_) => break candidate,
   676→                Err(e) if e.kind() == std::io::ErrorKind::AlreadyExists => continue,
   677→                Err(e) => return Err(format!("could not reserve asset path: {e}")),
   678→            }
   679→        },
   680→        Err(e) => return Err(format!("could not reserve asset path: {e}")),
   681→    };
   682→
   683→    let dest = assets_dir.join(&dest_name);
   684→    std::fs::copy(src, &dest).map_err(|e| format!("copy failed: {e}"))?;
   685→
   686→    // Return a path relative to the active file's directory when available.
   687→    let rel = if let Some(active) = active_file_path {
   688→        let from_dir = PathBuf::from(&active);
   689→        let from_dir = from_dir.parent().unwrap_or(Path::new(""));
   690→        relative_path_from(from_dir, &dest)
   691→    } else {
   692→        format!("assets/{dest_name}")
   693→    };
   694→
   695→    Ok(rel)
   696→}
