.modal-overlay {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 500;
  animation: fade-in 0.1s ease;
}

.modal-backdrop {
  position: absolute;
  inset: 0;
  background: rgba(0, 0, 0, 0.35);
  border: none;
  cursor: default;
}

.modal {
  position: relative;
  z-index: 1;
  background: var(--color-bg);
  border: 1px solid var(--color-border-strong);
  border-radius: 10px;
  padding: 20px 24px 18px;
  width: 320px;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.18);
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.modal-title {
  font-size: 13px;
  font-weight: 600;
  color: var(--color-text-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.modal-input {
  width: 100%;
  font-size: 14px;
  font-family: var(--font-ui);
  color: var(--color-text);
  background: var(--color-bg-sidebar);
  border: 1px solid var(--color-border-strong);
  border-radius: 6px;
  padding: 8px 10px;
  outline: none;
  transition: border-color 0.15s;
}

.modal-input:focus {
  border-color: var(--color-accent);
}

.modal-type-row {
  display: flex;
  align-items: center;
  gap: 10px;
}

.modal-type-label {
  font-size: 12px;
  color: var(--color-text-muted);
  flex-shrink: 0;
}

.modal-type-select {
  flex: 1;
  font-size: 13px;
  font-family: var(--font-ui);
  color: var(--color-text);
  background: var(--color-bg-sidebar);
  border: 1px solid var(--color-border-strong);
  border-radius: 5px;
  padding: 5px 8px;
  outline: none;
  cursor: pointer;
}

.modal-type-select:focus {
  border-color: var(--color-accent);
}

.modal-actions {
  display: flex;
  justify-content: flex-end;
  gap: 8px;
}

.modal-btn {
  font-size: 13px;
  padding: 6px 14px;
  border-radius: 6px;
  transition: background 0.15s;
}

.modal-cancel {
  color: var(--color-text-muted);
}

.modal-cancel:hover {
  background: var(--color-bg-hover);
}

.modal-confirm {
  color: var(--color-accent);
  border: 1px solid var(--color-accent);
}

.modal-confirm:hover:not(:disabled) {
  background: var(--color-accent-light);
}

.modal-confirm:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

@keyframes fade-in {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

