    20→const IMAGE_MIME = /^image\/(png|jpe?g|gif|webp|avif|svg\+xml)$/;
    21→
    22→interface EditorProps {
    23→  content?: string;
    24→  filePath?: string;
    25→  typewriterMode?: boolean;
