}

.context-menu-item-danger {
  color: #ef4444;
}

.context-menu-item-danger:hover {
  background: rgba(239, 68, 68, 0.1);
}

.context-menu-shortcut {
  font-size: 11px;
  color: var(--color-text-faint);
  margin-left: 12px;
  white-space: nowrap;
}

.context-menu-divider {
  height: 1px;
  background: var(--color-border);
  margin: 4px 0;
}

