import { useEffect, useRef, useState } from "react";
import type { FileNode } from "../lib/types";
import "./FileContextMenu.css";

interface FileContextMenuProps {
  node: FileNode | null;
  position: { x: number; y: number } | null;
  onNewFile?: (dirPath: string) => void;
  onRename?: (node: FileNode) => void;
  onDelete?: (node: FileNode) => void;
  onClose: () => void;
}

export function FileContextMenu({
  node,
  position,
  onNewFile,
  onRename,
  onDelete,
  onClose,
}: FileContextMenuProps) {
  const menuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!position) return;
    function handleClick(e: MouseEvent) {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        onClose();
      }
    }
    function handleKey(e: KeyboardEvent) {
      if (e.key === "Escape") {
        onClose();
      }
    }
    window.addEventListener("mousedown", handleClick);
    window.addEventListener("keydown", handleKey);
    return () => {
      window.removeEventListener("mousedown", handleClick);
      window.removeEventListener("keydown", handleKey);
    };
  }, [position, onClose]);

  if (!node || !position) return null;

  return (
    <div
      ref={menuRef}
      className="file-context-menu"
      style={{ top: `${position.y}px`, left: `${position.x}px` }}
    >
      {node.isDirectory && onNewFile && (
        <>
          <button
            type="button"
            className="context-menu-item"
            onClick={() => {
              onNewFile(node.path);
              onClose();
            }}
          >
            New file here
          </button>
          <div className="context-menu-divider" />
        </>
      )}
      {onRename && (
        <button
          type="button"
          className="context-menu-item"
          onClick={() => {
            onRename(node);
            onClose();
          }}
        >
          Rename <span className="context-menu-shortcut">F2</span>
        </button>
      )}
      {onDelete && (
        <button
          type="button"
          className="context-menu-item context-menu-item-danger"
          onClick={() => {
            onDelete(node);
            onClose();
          }}
        >
          Delete
        </button>
      )}
    </div>
  );
}

import {
  ArrowLeftRight,
  BookOpen,
  File,
  FileText,
  Folder,
  FolderOpen,
  LayoutTemplate,
  ListOrdered,
  StickyNote,
} from "lucide-react";
import { useEffect, useRef, useState } from "react";
import { FileContextMenu } from "./FileContextMenu";
import "./Sidebar.css";
import type { FileNode, GitStatus } from "../lib/types";

function ContentTypeIcon({ type }: { type: string | undefined }) {
  const props = { size: 13, className: "sidebar-file-icon" };
  switch (type) {
    case "post":
      return <FileText {...props} />;
    case "flow":
      return <ArrowLeftRight {...props} />;
    case "series":
      return <ListOrdered {...props} />;
    case "book":
      return <BookOpen {...props} />;
    case "page":
      return <LayoutTemplate {...props} />;
    case "note":
      return <StickyNote {...props} />;
    default:
      return <File {...props} />;
  }
}

interface SidebarProps {
  tree: FileNode[];
  selectedPath: string | null;
  renamingPath: string | null;
  visible: boolean;
  workspaceName: string | null;
  workspaceRoot: string | null;
  gitStatusMap: Map<string, GitStatus>;
  onSelect: (node: FileNode) => void;
  onOpenWorkspace: () => void;
  onOpenSwitcher: () => void;
  onNewFile: (dirPath: string) => void;
  onRename: (node: FileNode, newName: string) => void;
  onDelete: (node: FileNode) => void;
  onStartRename: (path: string) => void;
  onCancelRename: () => void;
}

interface FileItemProps {
  node: FileNode;
  depth: number;
  selectedPath: string | null;
  renamingPath: string | null;
  gitStatusMap: Map<string, GitStatus>;
  onSelect: (node: FileNode) => void;
  onNewFile: (dirPath: string) => void;
  onRename: (node: FileNode, newName: string) => void;
  onDelete: (node: FileNode) => void;
  onStartRename: (path: string) => void;
  onCancelRename: () => void;
  onContextMenu: (node: FileNode, x: number, y: number) => void;
}

function FileItem({
  node,
  depth,
  selectedPath,
  renamingPath,
  gitStatusMap,
  onSelect,
  onNewFile,
  onRename,
  onDelete,
  onStartRename,
  onCancelRename,
  onContextMenu,
}: FileItemProps) {
  const [expanded, setExpanded] = useState(true);
  const isSelected = node.path === selectedPath;
  const isRenaming = renamingPath === node.path;
  const isMarkdown = node.extension === ".md" || node.extension === ".mdx";
  const baseName = node.name.replace(/\.mdx?$/, "");
  const [renameValue, setRenameValue] = useState(baseName);
  const renameRef = useRef<HTMLInputElement>(null);
  const indent = `${12 + depth * 14}px`;

  useEffect(() => {
    if (isRenaming) {
      setRenameValue(baseName);
      renameRef.current?.focus();
      renameRef.current?.select();
    }
  }, [isRenaming, baseName]);

  if (node.isDirectory) {
    const DirIcon = expanded ? FolderOpen : Folder;
    return (
      <div>
        <div
          className="sidebar-dir-row"
          style={{ paddingLeft: indent }}
          onContextMenu={(e) => {
            e.preventDefault();
            onContextMenu(node, e.clientX, e.clientY);
          }}
        >
          <button type="button" className="sidebar-dir" onClick={() => setExpanded((v) => !v)}>
            <DirIcon size={13} className="sidebar-file-icon sidebar-dir-icon" />
            {node.name}
          </button>
        </div>
        {expanded &&
          node.children?.map((child) => (
            <FileItem
              key={child.path}
              node={child}
              depth={depth + 1}
              selectedPath={selectedPath}
              renamingPath={renamingPath}
              gitStatusMap={gitStatusMap}
              onSelect={onSelect}
              onNewFile={onNewFile}
              onRename={onRename}
              onDelete={onDelete}
              onStartRename={onStartRename}
              onCancelRename={onCancelRename}
              onContextMenu={onContextMenu}
            />
          ))}
      </div>
    );
  }

  if (!isMarkdown) return null;

  if (isRenaming) {
    return (
      <div className="sidebar-rename-row" style={{ paddingLeft: indent }}>
        <input
          ref={renameRef}
          className="sidebar-rename-input"
          value={renameValue}
          onChange={(e) => setRenameValue(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Enter" && renameValue.trim()) {
              onRename(node, renameValue.trim());
            } else if (e.key === "Escape") {
              onCancelRename();
            }
          }}
          onBlur={() => {
            if (renameValue.trim()) onRename(node, renameValue.trim());
            else onCancelRename();
          }}
        />
      </div>
    );
  }

  const displayName = node.title || baseName;
  const gitStatus = gitStatusMap.get(node.path);

  return (
    <div
      className={`sidebar-file-row ${isSelected ? "selected" : ""}`}
      onContextMenu={(e) => {
        e.preventDefault();
        onContextMenu(node, e.clientX, e.clientY);
      }}
    >
      <button
        type="button"
        className="sidebar-file"
        style={{ paddingLeft: indent }}
        onClick={() => onSelect(node)}
        onDoubleClick={() => onStartRename(node.path)}
        onKeyDown={(e) => {
          if (e.key === "F2") onStartRename(node.path);
        }}
      >
        <ContentTypeIcon type={node.contentType} />
        <span className={node.draft ? "sidebar-file-name draft" : "sidebar-file-name"}>
          {displayName}
        </span>
        {gitStatus && <span className={`git-dot git-dot-${gitStatus}`} title={gitStatus} />}
      </button>
    </div>
  );
}

export function Sidebar({
  tree,
  selectedPath,
  renamingPath,
  visible,
  workspaceName,
  workspaceRoot,
  gitStatusMap,
  onSelect,
  onOpenWorkspace,
  onOpenSwitcher,
  onNewFile,
  onRename,
  onDelete,
  onStartRename,
  onCancelRename,
}: SidebarProps) {
  const [contextMenu, setContextMenu] = useState<{
    node: FileNode;
    x: number;
    y: number;
  } | null>(null);

  function handleContextMenu(node: FileNode, x: number, y: number) {
    setContextMenu({ node, x, y });
  }

  function handleContextMenuRename(node: FileNode) {
    onStartRename(node.path);
  }

  return (
    <div className={`sidebar ${visible ? "" : "hidden"}`}>
      <div className="sidebar-header">
        <button
          type="button"
          className="sidebar-workspace-name"
          onClick={onOpenSwitcher}
          title="Switch workspace"
        >
          {workspaceName ?? "No workspace"}
        </button>
        <div className="sidebar-header-actions">
          {workspaceRoot && (
            <button
              type="button"
              className="sidebar-action-btn"
              title="New file (⌘N)"
              onClick={() => onNewFile(workspaceRoot)}
            >
              +
            </button>
          )}
          <button
            type="button"
            className="sidebar-open-btn"
            onClick={onOpenWorkspace}
            title="Open workspace"
          >
            ⊕
          </button>
        </div>
      </div>

      <div className="sidebar-tree">
        {tree.length === 0 ? (
          <div className="sidebar-empty">
            <p>No workspace open.</p>
            <button type="button" className="sidebar-open-workspace-btn" onClick={onOpenWorkspace}>
              Open folder
            </button>
          </div>
        ) : (
          tree.map((node) => (
            <FileItem
              key={node.path}
              node={node}
              depth={0}
              selectedPath={selectedPath}
              renamingPath={renamingPath}
              gitStatusMap={gitStatusMap}
              onSelect={onSelect}
              onNewFile={onNewFile}
              onRename={onRename}
              onDelete={onDelete}
              onStartRename={onStartRename}
              onCancelRename={onCancelRename}
              onContextMenu={handleContextMenu}
            />
          ))
        )}
      </div>

      {contextMenu && (
        <FileContextMenu
          node={contextMenu.node}
          position={{ x: contextMenu.x, y: contextMenu.y }}
          onNewFile={contextMenu.node.isDirectory ? onNewFile : undefined}
          onRename={handleContextMenuRename}
          onDelete={onDelete}
          onClose={() => setContextMenu(null)}
        />
      )}
    </div>
  );
}

